B3644 【模板】拓扑排序 / 家谱树

**题目描述**

有个人的家族很大，辈分关系很混乱，请你帮整理一下这种关系。给出每个人的后代的信息。输出一个序列，使得每个人的后辈都比那个人后列出。

**输入格式**

第 $$1$$ 行一个整数 $$N$$（$$1 \le N \le 100$$），表示家族的人数。接下来 $$N$$ 行，第 $$i$$ 行描述第 $$i$$ 个人的后代编号 $$a_{i,j}$$，表示 $$a_{i,j}$$ 是 $$i$$ 的后代。每行最后是 $$0$$ 表示描述完毕。

**输出格式**

输出一个序列，使得每个人的后辈都比那个人后列出。如果有多种不同的序列，输出任意一种即可。

输入 #1

```
5
0
4 5 1 0
1 0
5 3 0
3 0
```

输出 #1

```
2 4 5 3 1
```

### Python代码实现

```python
### kahn算法
import sys
from collections import deque

def toposort():
    q = deque()
    for i in range(1, n + 1):
        if din[i] == 0:
            q.append(i)
    while q:
        x = q.popleft()
        tp.append(x)
        for y in e[x]:
            din[y] -= 1
            if din[y] == 0:
                q.append(y)
    return len(tp) == n

# 读取 n, m
n, m = map(int, sys.stdin.readline().split())
# 初始化邻接表和入度数组
e = [[] for _ in range(n + 1)]
din = [0] * (n + 1)
tp = []

# 读取边信息
for _ in range(m):
    a, b = map(int, sys.stdin.readline().split())
    e[a].append(b)
    din[b] += 1

# 执行拓扑排序并输出结果
if not toposort():
    print(-1)
else:
    print(*tp)
```

### C++代码实现

```c++
// Kahn算法 O(n)
#include <iostream>
#include <cstring>
#include <algorithm>
#include <queue>
using namespace std;
const int N = 100010;
int n,m,a,b;
vector<int> e[N], tp;
int din[N];

bool toposort(){
  queue<int> q;
  for(int i = 1; i <= n; i++)
    if(din[i]==0) q.push(i);
  while(q.size()){
    int x=q.front(); q.pop();
    tp.push_back(x);
    for(auto y : e[x]){
      if(--din[y]==0) q.push(y);
    }
  }
  return tp.size() == n;
}
int main(){
  cin >> n >> m;
  for(int i=0; i<m; i++){
    cin >> a >> b;
    e[a].push_back(b);
    din[b]++;
  }
  if(!toposort()) puts("-1");
  else for(auto x:tp)printf("%d ",x);
  return 0;
}
```

